"use client";
import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
const steps=["Scanning notes","Checking route","Review complete"];
export default function ApertureDotLoader(){const [step,setStep]=useState(0);const reduced=useReducedMotion();const advance=()=>setStep(step===2?0:step+1);return <section className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 text-center shadow-[0_10px_28px_rgba(17,17,17,.06)]"><p className="text-xs font-extrabold uppercase tracking-[.14em] text-[#4a4a4f]">review pass</p><div className="relative mx-auto mt-5 flex w-40 justify-between">{steps.map((_,i)=><i key={i} aria-hidden className="h-6 w-6 rounded-full border border-[#ececee] bg-[#f4f5f6]"/>)}<motion.i aria-hidden className="absolute top-0 h-6 w-6 rounded-full bg-[#53e8d4]" animate={{x:step*68}} transition={reduced?{duration:0}:{type:"spring",stiffness:330,damping:25}}/></div><motion.p key={step} initial={{opacity:0}} animate={{opacity:1}} transition={{duration:reduced?.12:.14}} aria-live="polite" className="mt-5 text-sm font-bold text-[#111]">{steps[step]} · {step+1} of 3</motion.p><button type="button" onClick={advance} className="mt-4 min-h-11 rounded-xl bg-[#111] px-4 text-sm font-bold text-white outline-offset-4 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">{step===2?"Restart review":"Advance review"}</button></section>}
